patch:
--- a/priority_encoder.vhd
+++ b/priority_encoder.vhd
@@ -1,15 +1,15 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity priority_encoder is
   port (
     req0, req1, req2, req3 : in std_logic;
     priority : out std_logic_vector(1 downto 0)
   );
 end priority_encoder;

 architecture rtl of priority_encoder is
 begin
-  process(req0)
+  process(req0, req1, req2, req3)
   begin
     if req3 = '1' then
       priority <= "11";
     elsif req2 = '1' then
       priority <= "10";
     elsif req1 = '1' then
       priority <= "01";
     else
       priority <= "00";
     end if;
   end process;

 end rtl;

